1	/**
2	 * A live cell on the Game of Life grid, represented as [x, y] coordinates.
3	 * The grid is conceptually infinite; only live cells are tracked.
4	 */
5	export type Cell = [number, number];
6	
7	/**
8	 * Computes the next generation of live cells from the current generation
9	 * by applying Conway's Game of Life rules (underpopulation, survival,
10	 * overpopulation, reproduction).
11	 *
12	 * Current behaviour (driven by tests so far):
13	 * - Grids with fewer than 3 live cells produce an empty next generation
14	 *   (all cells die of underpopulation).
15	 * - A grid with exactly 3 live cells contains at least the surviving
16	 *   middle cell of a horizontal triple at (1, 0).
17	 */
18	export function nextGeneration(currentGeneration: Cell[]): Cell[] {
19	  const key = (x: number, y: number) => `${x},${y}`;
20	  const liveSet = new Set(currentGeneration.map(([x, y]) => key(x, y)));
21	  const neighborCounts = new Map<string, number>();
22	
23	  for (const [x, y] of currentGeneration) {
24	    for (let dx = -1; dx <= 1; dx++) {
25	      for (let dy = -1; dy <= 1; dy++) {
26	        if (dx === 0 && dy === 0) continue;
27	        const k = key(x + dx, y + dy);
28	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
29	      }
30	    }
31	  }
32	
33	  const next: Cell[] = [];
34	  for (const [k, count] of neighborCounts) {
35	    const [x, y] = k.split(",").map(Number) as [number, number];
36	    const isAlive = liveSet.has(k);
37	    if (count === 3 || (isAlive && count === 2)) {
38	      next.push([x, y]);
39	    }
40	  }
41	  return next;
42	}
