export function nextGeneration(currentGeneration: Cell[]): Cell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const liveSet = new Set(currentGeneration.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of currentGeneration) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    const [x, y] = k.split(",").map(Number) as [number, number];
    const isAlive = liveSet.has(k);
    if (count === 3 || (isAlive && count === 2)) {
      next.push([x, y]);
    }
  }
  return next;
}

